const hours = ["8 AM", "9 AM", "10 AM", "11 AM", "12 PM", "1 PM", "2 PM", "3 PM", "4 PM", "5 PM", "6 PM"];
let teamTotal = 0;
let lastHour = "";
let agentsProcessed = [];

const inputItems = $input.all();

// Calculate totals and real-time average
inputItems.forEach(item => {
  let row = item.json;
  let agentSum = 0;
  let agentName = row["Agent"] || row["Agente"] || row["agente"] || "Unknown";

  hours.forEach(h => {
    let val = parseInt(row[h]);
    if (!isNaN(val)) {
      agentSum += val;
      lastHour = h;
    }
  });

  if (agentSum > 0) {
    teamTotal += agentSum;
    agentsProcessed.push({ name: agentName, tickets: agentSum });
  }
});

const teamAverage = agentsProcessed.length > 0 ? teamTotal / agentsProcessed.length : 0;


// --- SYNCHRONIZED SLA LOGIC (Power BI Equivalent) ---
const hourMapping = {
  "8 AM": 1, "9 AM": 2, "10 AM": 3, "11 AM": 4, 
  "12 PM": 5, "1 PM": 6, "2 PM": 7, "3 PM": 8, 
  "4 PM": 9, "5 PM": 10, "6 PM": 11
};

const hoursSinceStart = hourMapping[lastHour] || 1;
const expectedGoal = hoursSinceStart * 5.6;
const slaResult = (teamAverage / expectedGoal).toFixed(2);

// Shift logic
let outgoingShift = "";
if (lastHour === "1 PM") outgoingShift = "6 AM - 2 PM";
else if (lastHour === "2 PM") outgoingShift = "7 AM - 3 PM";
else if (lastHour === "3 PM") outgoingShift = "8 AM - 4 PM";
else if (lastHour === "5 PM") outgoingShift = "10 AM - 6 PM";

const isCriticalHour = (outgoingShift !== "");

// 2. Step Two: Build the dynamic status table (Monospace)
let tableText = "```\n"; 
tableText += "AGENT           | TKS | STATUS\n";
tableText += "------------------------------\n";

agentsProcessed.forEach(ag => {
  let statusEmoji = "🔴"; // Below 80% of average

  if (ag.tickets >= teamAverage) {
    statusEmoji = "🟢"; // Above average
  } 
  else if (ag.tickets >= (teamAverage * 0.8)) {
    statusEmoji = "🟡"; // Close to average (80%+)
  }

  const fixedName = ag.name.substring(0, 15).padEnd(15, ' ');
  const fixedTickets = ag.tickets.toString().padStart(3, ' ');
  tableText += `${fixedName} | ${fixedTickets} | ${statusEmoji}\n`;
});

tableText += "------------------------------\n";
tableText += `TOTAL TEAM      | ${teamTotal.toString().padStart(3, ' ')} | 🚀\n`;
tableText += "```";

// 3. Improved n8n Output Mapping
const output = inputItems.map((item, index) => {
  // We create the summary only for the first item to avoid redundancy
  const summary = index === 0 ? {
    table_content: tableText,
    grand_total: teamTotal,
    average_productivity: teamAverage.toFixed(1),
    cutoff_time: lastHour,
    sla_score: slaResult, // The dynamic value matching Power BI
    shift_name: outgoingShift,
    is_critical: isCriticalHour
  } : null;

  return {
    json: {
      // Tickets per agent for the Excel PUT
      total_val: (index < agentsProcessed.length) ? agentsProcessed[index].tickets : null,

      // Data for Gemini and Slack nodes
      slack_message: summary, 
      data_for_ai: summary 
    }
  };
});

// Extra item for Grand Total row in Excel
output.push({ 
  json: { 
    total_val: teamTotal, 
    is_grand_total: true 
  } 
});

return output;
